166→  justify-content: center;
167→  width: 32px;
168→  height: 32px;
169→  border-radius: var(--radius-sm);
170→  color: var(--color-text-secondary);
171→  transition: background var(--duration-fast), color var(--duration-fast);
172→  position: relative;
173→  cursor: pointer;
174→}
175→
176→.toolPaletteBtn:hover {
177→  background: rgba(0, 0, 0, 0.06);
178→  color: var(--color-text-primary);
179→}
180→
181→.toolPaletteBtn:disabled {
182→  opacity: 0.35;
183→  cursor: not-allowed;
184→}
185→
186→.toolPaletteBtn:disabled:hover {
187→  background: transparent;
188→  color: var(--color-text-secondary);
189→}
190→
191→.toolPaletteBtnActive {
192→  composes: toolPaletteBtn;
193→  background: var(--color-accent-subtle);
194→  color: var(--color-accent);
195→}
196→
197→.toolPaletteBtnActive:hover {
