199→}
200→
201→.toolPaletteIcon {
202→  width: 18px;
203→  height: 18px;
204→  display: block;
205→}
206→
207→/* Fixture palette */
208→.fixturePalette {
209→  display: flex;
210→  align-items: center;
211→  gap: 1px;
212→  padding: 0 var(--space-sm);
213→  flex-shrink: 0;
214→  border-left: 1px solid var(--color-border-subtle);
215→}
216→
217→.fixturePaletteLabel {
218→  font-size: 10px;
219→  font-weight: 600;
220→  color: var(--color-text-secondary);
221→  margin-right: 4px;
