265→  .group {
266→    padding: 0 var(--space-xs);
267→  }
268→  .toolPalette {
269→    padding: 0 var(--space-xs);
270→  }
271→  .fixturePalette {
272→    padding: 0 var(--space-xs);
273→  }
274→  .fixturePaletteLabel {
275→    display: none;
