 1→import { useCallback } from 'react';
 2→import styles from './InputField.module.css';
 3→
 4→export default function InputField({ label, value, onChange, type = 'text', suffix, readOnly, step }) {
 5→  const handleChange = useCallback((e) => {
 6→    const val = type === 'number' ? parseFloat(e.target.value) : e.target.value;
 7→    if (type === 'number' && isNaN(val)) return;
 8→    onChange(val);
 9→  }, [onChange, type]);
10→
11→  const inputClass = [
12→    styles.input,
13→    type === 'number' ? styles.inputNumber : '',
14→    readOnly ? styles.inputReadonly : '',
15→  ].filter(Boolean).join(' ');
16→
17→  return (
18→    <div className={styles.field}>
19→      <label className={styles.label}>{label}</label>
20→      <div className={styles.inputWrap}>
21→        <input
22→          type={type}
23→          value={value}
24→          onChange={handleChange}
25→          readOnly={readOnly}
26→          step={step}
27→          className={inputClass}
28→        />
29→        {suffix && <span className={styles.suffix}>{suffix}</span>}
30→      </div>
31→    </div>
32→  );
33→}
