 28→function useUnits() {
 29→  const [unit, setUnit] = useState('mm');
 30→  const isMm = unit === 'mm';
 31→  return {
 32→    unit,
 33→    setUnit,
 34→    suffix: isMm ? 'mm' : 'm',
 35→    toDisplay: (mm) => isMm ? +mm.toFixed(1) : +(mm / 1000).toFixed(4),
 36→    fromDisplay: (v) => isMm ? v : v * 1000,
 37→    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
 38→  };
 39→}
